// Secure "Remember Me" Authentication System

const crypto = require('crypto');
const express = require('express');
const cookieParser = require('cookie-parser');

const app = express();
app.use(express.json());
app.use(express.urlencoded({ extended: true }));
app.use(cookieParser(process.env.COOKIE_SECRET || crypto.randomBytes(32).toString('hex')));

// --- In-memory stores (replace with database in production) ---
const users = new Map();
const rememberMeTokens = new Map(); // tokenId -> { userId, tokenHash, series, expiresAt, createdAt }

// --- Configuration ---
const CONFIG = {
  REMEMBER_ME_DAYS: 30,
  TOKEN_BYTES: 32,
  SERIES_BYTES: 16,
  SESSION_DURATION_MS: 24 * 60 * 60 * 1000, // 1 day session
  REMEMBER_ME_DURATION_MS: 30 * 24 * 60 * 60 * 1000,
  BCRYPT_LIKE_ITERATIONS: 100000,
  MAX_FAILED_ATTEMPTS: 5,
  LOCKOUT_DURATION_MS: 15 * 60 * 1000, // 15 minutes
};

// --- Secure Password Hashing (using PBKDF2 as a built-in alternative to bcrypt) ---
function hashPassword(password) {
  const salt = crypto.randomBytes(16).toString('hex');
  const hash = crypto.pbkdf2Sync(password, salt, CONFIG.BCRYPT_LIKE_ITERATIONS, 64, 'sha512').toString('hex');
  return `${salt}:${CONFIG.BCRYPT_LIKE_ITERATIONS}:${hash}`;
}

function verifyPassword(password, storedHash) {
  const [salt, iterations, hash] = storedHash.split(':');
  const candidateHash = crypto.pbkdf2Sync(password, salt, parseInt(iterations), 64, 'sha512').toString('hex');
  return crypto.timingSafeEqual(Buffer.from(hash, 'hex'), Buffer.from(candidateHash, 'hex'));
}

// --- Secure Token Generation & Management ---
// Uses the "series token" pattern to detect token theft
// Reference: https://paragonie.com/blog/2015/04/secure-authentication-php-with-long-term-persistence

function generateSecureToken() {
  return crypto.randomBytes(CONFIG.TOKEN_BYTES).toString('base64url');
}

function generateSeries() {
  return crypto.randomBytes(CONFIG.SERIES_BYTES).toString('base64url');
}

function hashToken(token) {
  return crypto.createHmac('sha256', process.env.TOKEN_HMAC_SECRET || 'change-this-secret-in-production')
    .update(token)
    .digest('hex');
}

function createRememberMeToken(userId) {
  const token = generateSecureToken();
  const series = generateSeries();
  const tokenHash = hashToken(token);
  const tokenId = crypto.randomUUID();

  rememberMeTokens.set(tokenId, {
    userId,
    tokenHash,
    series,
    expiresAt: Date.now() + CONFIG.REMEMBER_ME_DURATION_MS,
    createdAt: Date.now(),
  });

  // Return the values to be stored in the cookie
  // We store tokenId + series + token (NOT the password hash)
  return { tokenId, series, token };
}

function validateAndRotateRememberMeToken(tokenId, series, token) {
  const stored = rememberMeTokens.get(tokenId);

  if (!stored) {
    return { valid: false, reason: 'token_not_found' };
  }

  // Check expiration
  if (Date.now() > stored.expiresAt) {
    rememberMeTokens.delete(tokenId);
    return { valid: false, reason: 'token_expired' };
  }

  // Check series match - if series doesn't match, this is suspicious
  if (stored.series !== series) {
    // Possible token theft - invalidate ALL tokens for this user
    invalidateAllUserTokens(stored.userId);
    return { valid: false, reason: 'series_mismatch_possible_theft' };
  }

  // Verify token using timing-safe comparison
  const candidateHash = hashToken(token);
  const storedHashBuf = Buffer.from(stored.tokenHash, 'hex');
  const candidateHashBuf = Buffer.from(candidateHash, 'hex');

  if (storedHashBuf.length !== candidateHashBuf.length ||
      !crypto.timingSafeEqual(storedHashBuf, candidateHashBuf)) {
    // Token mismatch with correct series = likely token theft
    invalidateAllUserTokens(stored.userId);
    return { valid: false, reason: 'token_mismatch_possible_theft' };
  }

  // Token is valid - rotate it (issue new token, keep same series)
  const newToken = generateSecureToken();
  const newTokenHash = hashToken(newToken);

  rememberMeTokens.set(tokenId, {
    ...stored,
    tokenHash: newTokenHash,
    createdAt: Date.now(),
    // Keep same series and expiration
  });

  return {
    valid: true,
    userId: stored.userId,
    newToken, // Caller must set new cookie with this
  };
}

function invalidateAllUserTokens(userId) {
  for (const [tokenId, data] of rememberMeTokens.entries()) {
    if (data.userId === userId) {
      rememberMeTokens.delete(tokenId);
    }
  }
  console.warn(`[SECURITY] All remember-me tokens invalidated for user: ${userId}`);
}

function invalidateToken(tokenId) {
  rememberMeTokens.delete(tokenId);
}

// --- Rate Limiting / Brute Force Protection ---
const loginAttempts = new Map(); // ip -> { count, lastAttempt, lockedUntil }

function checkRateLimit(ip) {
  const attempts = loginAttempts.get(ip);
  if (!attempts) return { allowed: true };

  if (attempts.lockedUntil && Date.now() < attempts.lockedUntil) {
    const remainingMs = attempts.lockedUntil - Date.now();
    return { allowed: false, retryAfterMs: remainingMs };
  }

  // Reset if lockout has expired
  if (attempts.lockedUntil && Date.now() >= attempts.lockedUntil) {
    loginAttempts.delete(ip);
    return { allowed: true };
  }

  return { allowed: true };
}

function recordFailedAttempt(ip) {
  const attempts = loginAttempts.get(ip) || { count: 0, lastAttempt: 0 };
  attempts.count += 1;
  attempts.lastAttempt = Date.now();

  if (attempts.count >= CONFIG.MAX_FAILED_ATTEMPTS) {
    attempts.lockedUntil = Date.now() + CONFIG.LOCKOUT_DURATION_MS;
    console.warn(`[SECURITY] IP ${ip} locked out after ${attempts.count} failed attempts`);
  }

  loginAttempts.set(ip, attempts);
}

function resetFailedAttempts(ip) {
  loginAttempts.delete(ip);
}

// --- Session Management (simplified - use express-session in production) ---
const sessions = new Map();

function createSession(userId) {
  const sessionId = crypto.randomBytes(32).toString('base64url');
  sessions.set(sessionId, {
    userId,
    createdAt: Date.now(),
    expiresAt: Date.now() + CONFIG.SESSION_DURATION_MS,
  });
  return sessionId;
}

function validateSession(sessionId) {
  const session = sessions.get(sessionId);
  if (!session) return null;
  if (Date.now() > session.expiresAt) {
    sessions.delete(sessionId);
    return null;
  }
  return session;
}

function destroySession(sessionId) {
  sessions.delete(sessionId);
}

// --- Cookie Helpers ---
function setRememberMeCookie(res, tokenId, series, token) {
  // Combine into a single cookie value
  const cookieValue = `${tokenId}|${series}|${token}`;

  res.cookie('remember_me', cookieValue, {
    maxAge: CONFIG.REMEMBER_ME_DURATION_MS,
    httpOnly: true,       // Not accessible via JavaScript
    secure: process.env.NODE_ENV === 'production', // HTTPS only in production
    sameSite: 'lax',      // CSRF protection
    path: '/',
    signed: true,         // Tamper detection
  });
}

function setSessionCookie(res, sessionId) {
  res.cookie('session_id', sessionId, {
    httpOnly: true,
    secure: process.env.NODE_ENV === 'production',
    sameSite: 'lax',
    path: '/',
    signed: true,
    // No maxAge = session cookie (expires when browser closes, unless remember-me restores it)
  });
}

function clearRememberMeCookie(res) {
  res.clearCookie('remember_me', {
    httpOnly: true,
    secure: process.env.NODE_ENV === 'production',
    sameSite: 'lax',
    path: '/',
    signed: true,
  });
}

function clearSessionCookie(res) {
  res.clearCookie('session_id', {
    httpOnly: true,
    secure: process.env.NODE_ENV === 'production',
    sameSite: 'lax',
    path: '/',
    signed: true,
  });
}

function parseRememberMeCookie(cookieValue) {
  if (!cookieValue || typeof cookieValue !== 'string') return null;
  const parts = cookieValue.split('|');
  if (parts.length !== 3) return null;
  return { tokenId: parts[0], series: parts[1], token: parts[2] };
}

// --- Middleware: Auto-login via Remember Me ---
function autoLoginMiddleware(req, res, next) {
  // If already authenticated via session, skip
  const sessionId = req.signedCookies.session_id;
  if (sessionId) {
    const session = validateSession(sessionId);
    if (session) {
      req.userId = session.userId;
      req.authenticated = true;
      return next();
    }
    // Session expired, clear it
    clearSessionCookie(res);
  }

  // Try remember-me cookie
  const rememberMeValue = req.signedCookies.remember_me;
  if (!rememberMeValue) {
    req.authenticated = false;
    return next();
  }

  const parsed = parseRememberMeCookie(rememberMeValue);
  if (!parsed) {
    clearRememberMeCookie(res);
    req.authenticated = false;
    return next();
  }

  const result = validateAndRotateRememberMeToken(parsed.tokenId, parsed.series, parsed.token);

  if (!result.valid) {
    clearRememberMeCookie(res);

    if (result.reason === 'series_mismatch_possible_theft' || result.reason === 'token_mismatch_possible_theft') {
      console.error(`[SECURITY ALERT] Possible remember-me token theft detected! Reason: ${result.reason}, IP: ${req.ip}`);
      // In production, you might want to notify the user via email
    }

    req.authenticated = false;
    return next();
  }

  // Valid token - create new session and rotate the remember-me token
  const newSessionId = createSession(result.userId);
  setSessionCookie(res, newSessionId);
  setRememberMeCookie(res, parsed.tokenId, parsed.series, result.newToken);

  req.userId = result.userId;
  req.authenticated = true;
  req.autoLoggedIn = true; // Flag that this was an auto-login

  console.log(`[AUTH] Auto-login successful for user: ${result.userId} from IP: ${req.ip}`);
  next();
}

// --- Middleware: Require authentication ---
function requireAuth(req, res, next) {
  if (!req.authenticated) {
    return res.status(401).json({ error: 'Authentication required' });
  }
  next();
}

// Require fresh login (not auto-login) for sensitive operations
function requireFreshAuth(req, res, next) {
  if (!req.authenticated || req.autoLoggedIn) {
    return res.status(401).json({
      error: 'Fresh authentication required for this operation',
      requireReauth: true,
    });
  }
  next();
}

