// Login
app.post('/api/login', (req, res) => {
  const { username, password, rememberMe } = req.body;
  const clientIp = req.ip;

  // Rate limiting check
  const rateCheck = checkRateLimit(clientIp);
  if (!rateCheck.allowed) {
    return res.status(429).json({
      error: 'Too many failed login attempts. Please try again later.',
      retryAfterMs: rateCheck.retryAfterMs,
    });
  }

  if (!username || !password) {
    return res.status(400).json({ error: 'Username and password are required' });
  }

  const user = users.get(username);

  // Use constant-time comparison approach - always hash even if user not found
  if (!user) {
    // Perform a dummy hash to prevent timing attacks that reveal user existence
    hashPassword(password);
    recordFailedAttempt(clientIp);
    return res.status(401).json({ error: 'Invalid username or password' });
  }

  const passwordValid = verifyPassword(password, user.passwordHash);

  if (!passwordValid) {
    recordFailedAttempt(clientIp);
    return res.status(401).json({ error: 'Invalid username or password' });
  }

  // Successful login
  resetFailedAttempts(clientIp);

  // Create session
  const sessionId = createSession(user.userId);
  setSessionCookie(res, sessionId);

  // Handle "Remember Me"
  if (rememberMe) {
    const { tokenId, series, token } = createRememberMeToken(user.userId);
    setRememberMeCookie(res, tokenId, series, token);
    console.log(`[AUTH] Remember-me token created for user: ${user.userId}`);
  }

  console.log(`[AUTH] Login successful for user: ${user.username} (${user.userId}) from IP: ${clientIp}`);

  res.json({
    message: 'Login successful',
    userId: user.userId,
    username: user.username,
  });
});

// Logout
app.post('/api/logout', autoLoginMiddleware, (req, res) => {
  // Destroy session
  const sessionId = req.signedCookies.session_id;
  if (sessionId) {
    destroySession(sessionId);
  }

  // Invalidate remember-me token
  const rememberMeValue = req.signedCookies.remember_me;
  if (rememberMeValue) {
    const parsed = parseRememberMeCookie(rememberMeValue);
    if (parsed) {
      invalidateToken(parsed.tokenId);
    }
  }

  clearSessionCookie(res);
  clearRememberMeCookie(res);

  res.json({ message: 'Logged out successfully' });
});

// Logout from all devices
app.post('/api/logout-all', autoLoginMiddleware, requireAuth, (req, res) => {
  // Invalidate all remember-me tokens for this user
  invalidateAllUserTokens(req.userId);

  // Destroy current session
  const sessionId = req.signedCookies.session_id;
  if (sessionId) {
    destroySession(sessionId);
  }

  // Destroy all sessions for this user
  for (const [sid, session] of sessions.entries()) {
    if (session.userId === req.userId) {
      sessions.delete(sid);
    }
  }

  clearSessionCookie(res);
  clearRememberMeCookie(res);

  res.json({ message: 'Logged out from all devices' });
});

