app.post('/api/change-password', autoLoginMiddleware, requireFreshAuth, (req, res) => {
  const { currentPassword, newPassword } = req.body;

  if (!currentPassword || !newPassword) {
    return res.status(400).json({ error: 'Current and new passwords are required' });
  }

  if (newPassword.length < 8) {
    return res.status(400).json({ error: 'New password must be at least 8 characters' });
  }

  let foundUser = null;
  let foundUsername = null;
  for (const [username, user] of users.entries()) {
    if (user.userId === req.userId) {
      foundUser = user;
      foundUsername = username;
      break;
    }
  }

  if (!foundUser || !verifyPassword(currentPassword, foundUser.passwordHash)) {
    return res.status(401).json({ error: 'Current password is incorrect' });
  }

  // Update password
  foundUser.passwordHash = hashPassword(newPassword);
  users.set(foundUsername, foundUser);

  // Invalidate all remember-me tokens (force re-authentication)
  invalidateAllUserTokens(req.userId);

  // Clear current remember-me cookie
  clearRememberMeCookie(res);

  res.json({ message: 'Password changed successfully. Please log in again on other devices.' });
});

