// --- Periodic Cleanup (run on interval in production) ---
function cleanupExpiredTokens() {
  const now = Date.now();
  let cleaned = 0;

  for (const [tokenId, data] of rememberMeTokens.entries()) {
    if (now > data.expiresAt) {
      rememberMeTokens.delete(tokenId);
      cleaned++;
    }
  }

  for (const [sessionId, session] of sessions.entries()) {
    if (now > session.expiresAt) {
      sessions.delete(sessionId);
      cleaned++;
    }
  }

  // Clean up old rate limit entries
  for (const [ip, attempts] of loginAttempts.entries()) {
    if (attempts.lockedUntil && now > attempts.lockedUntil + CONFIG.LOCKOUT_DURATION_MS) {
      loginAttempts.delete(ip);
      cleaned++;
    }
  }

  if (cleaned > 0) {
    console.log(`[CLEANUP] Removed ${cleaned} expired entries`);
  }
}

// Run cleanup every hour
